class app {
    constructor(){
        var constraints, stream, cam, capture, cams, plate, viewer, context, update, image, imghr, imgwr, ratio, hide;
        const about = document.querySelector("#about");
        const ab_close = about.querySelector("#about-close");
        const welcome = document.querySelector("#welcome");
        const apptana = document.querySelector("#gunjan-apptana");
        const launcher = welcome.querySelector("#launcher");
        const player = apptana.querySelector("#player");
        const header = apptana.querySelector("#apptana-header");
        const btn_switch = player.querySelector("#btn-switch");
        const btn_capture = player.querySelector("#btn-capture");
        const text = "Selfie with Gunjan ❤";

        (()=>{

            var initiators  = document.querySelectorAll(".about-initiator");
            initiators.forEach((elem)=>{
                elem.onclick = () => {
                    document.body.classList.add("about-visible");
                }
            });
            ab_close.onclick = () => {
                document.body.classList.add("about-closing");
                setTimeout(()=>{
                    document.body.classList.remove("about-closing");
                    document.body.classList.remove("about-visible");
                }, 490);
            }
        })();
        const fetchCameras = ()=>{
            constraints = navigator.mediaDevices.getSupportedConstraints("video");
            return new Promise((resolve, reject)=>{
                navigator.mediaDevices.enumerateDevices("video").then((res)=>{
                    let cameras = res.filter(function(data){
                        return data.kind == "videoinput";
                    });
                    resolve(cameras);
                }).catch((e)=>{
                   reject(e);
                });
            });
        };

        const checkPermission = () =>{
            cam = cams[0];
            return new Promise((resolve, reject)=>{
                navigator.permissions.query({name: "camera"}).then((res)=>{
                    navigator.mediaDevices.getUserMedia({
                        video: true,
                        deviceId: cam.deviceId
                    }).then((stream)=>{
                        resolve(stream)
                    }).catch((e)=>{
                        reject(e);
                    });
                }).catch((e)=>{
                    reject(e);
                });
            });
        };

        const convertToBlob = (dataURL) =>{
                var dat = dataURL.split(",");
                var type = dat[0].substring(
                    dat[0].indexOf(":") + 1, dat[0].indexOf(";base64")
                    );
                var data = dat[1];
                data = atob(data);
                var ia = new Uint8Array(data.length);
                for(let i = 0; i < ia.length; i++){
                    ia[i] = data.charCodeAt(i);
                }
                var blob = new Blob([ia], {type: type});
                return blob;
        }
        const show = () => {
            update = requestAnimationFrame(show);
            ratio =  plate.videoHeight/plate.videoWidth;
            let width = apptana.offsetWidth;
            
            if(width > plate.videoWidth){
                width = plate.videoWidth;
            }
            let height = ratio * width;
            viewer.width = width;
            viewer.height = height;
            
            if(viewer.height > window.innerHeight){
                height = window.innerHeight;
                viewer.height = height;
                viewer.width = height / ratio;
            }
            

            
            let nw = imgwr*viewer.height;
            let nh = imghr * nw;
            let x = -10;
            if(nw > viewer.width/2){
                x = -nw /2;
            }
            
            
            

            context.save();
            context.translate(viewer.width, 0);
            context.scale(-1, 1);
            context.drawImage(plate, 0, 0, viewer.width, viewer.height);
            context.restore();
            context.drawImage(image, x, viewer.height + 20, nw, -nh);
            

            context.font = "12px Quicksand";
            context.fillStyle = "#fff";
            var measure = context.measureText(text).width;
            context.beginPath();
            context.fillText(text, (viewer.width/2) - (measure/2), viewer.height - 13);
            context.closePath();
        }

        const saveImage = () => {
            cancelAnimationFrame(update);
            viewer.toBlob(function(data){
                var link = window.URL.createObjectURL(data);
                capture.href = link;
                capture.download = `selfie-with-gunjan-${Date.now()}.png`;
                player.classList.add("capturing");
                setTimeout(()=>{
                    player.classList.remove("capturing");
                    capture.click();
                    update = requestAnimationFrame(show);
                }, 1000)
            }, "image/png");
            
        }

        const switchCam =  () => {
            cancelAnimationFrame(update);
            context.clearRect(0, 0, viewer.width, viewer.height);
            plate.srcObject.getVideoTracks().forEach((track)=>{
                track.stop();
            });
            let id = cams.findIndex((data)=>{
                return data.deviceId == cam.deviceId;
            });
            id++;
            if(id >= cams.length){
                id = 0;
            }
            cam = cams[id];
            navigator.mediaDevices.getUserMedia({
                video: true,
                deviceId: cam.deviceId
            }).then((stream)=>{
                plate.srcObject = stream;
                update = requestAnimationFrame(show);
            }).catch((e)=>{
                alert("Something went wrong!")
            });
        }

        const setControls = () => {
            window.onclick = ()=>{
                clearTimeout(hide);
                header.classList.remove("hidden");
                hide = setTimeout(()=>{
                    header.classList.add("hidden");
                }, 2000);
            };
            btn_capture.onclick = saveImage;
            btn_switch.onclick = switchCam;
        }

        const start = (res) => {
            stream = res;
            plate = document.createElement("video");
            plate.autoplay = true;
            plate.classList.add("overlay");
            plate.srcObject = stream;

            capture = document.createElement("a");
            capture.download = "";
            image = new Image();
            image.onload = () => {
                imgwr = image.naturalWidth / image.naturalHeight;
                imghr = image.naturalHeight /image.naturalWidth;
                launcher.onclick = () =>{
                    viewer = document.createElement("canvas");
                    context = viewer.getContext("2d");
                    apptana.appendChild(plate);
                    player.appendChild(viewer);
                    update = requestAnimationFrame(show);

                    welcome.classList.add("inactive");
                    apptana.classList.remove("inactive");
                    setControls();
                }
                launcher.innerHTML = "Lets Start!";
               
            }
            const dataURL = "data:image/png;base64,";
                image.src = URL.createObjectURL(
                    convertToBlob(dataURL)
                    );
        }

        const initiate = () =>{
            fetchCameras().then(function(cameras){
                cams = cameras;
                if(cams.length == 0){
                    launcher.innerHTML = "Oops!";
                    alert("No camera detected!");
                    return;
                }
                checkPermission().then((res)=>{
                    console.log(res);
                    start(res);
                }).catch((e)=>{
                    alert("Failed to grant permission!");
                    launcher.innerHTML = "Try again!";
                    launcher.onclick = initiate;
                });
            });
        }
        initiate();
    }
}

window.onload = function(){
    const runtime = new app();
}
